        Button(
            onClick = {
                isRunning = false
                val secs = seconds
                seconds = 0
                val minutes = secs / 60.0
                val kcal = (liveKcalPerMin * minutes).coerceAtLeast(0.0)
                val rounded = kcal.roundToInt()
                if (secs > 0) {
