                        style = MaterialTheme.typography.bodyLarge
                    )
                    Text(
                        text = "Айда ещё",
                        style = MaterialTheme.typography.bodyMedium
                    )
                }
            }
        }

        Spacer(modifier = Modifier.height(20.dp))

        Button(onClick = { navController.navigate("exercises") }) {
            Text("Назад к списку")
        }
    }
}

@SuppressLint("SetJavaScriptEnabled")
@Composable
private fun ExerciseVideoPreview(videoUrl: String) {
    val html = remember(videoUrl) { buildVideoPreviewHtml(videoUrl) }

    Card(
        modifier = Modifier.fillMaxWidth(),
        shape = RoundedCornerShape(20.dp),
        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface)
    ) {
        AndroidView(
            modifier = Modifier
                .fillMaxWidth()
                .height(220.dp),
            factory = { context ->
                WebView(context).apply {
                    setBackgroundColor(Color.TRANSPARENT)
                    settings.javaScriptEnabled = true
                    settings.domStorageEnabled = true
                    settings.mediaPlaybackRequiresUserGesture = false
                    settings.cacheMode = WebSettings.LOAD_DEFAULT
                    webChromeClient = WebChromeClient()
                    webViewClient = WebViewClient()
                }
            },
            update = { webView ->
                webView.loadDataWithBaseURL(
                    null,
                    html,
                    "text/html",
                    "UTF-8",
                    null
                )
            }
        )
    }
}

private fun buildVideoPreviewHtml(videoUrl: String): String {
    val embedUrl = videoUrl.toYouTubeEmbedUrl()
    val sourceUrl = embedUrl ?: videoUrl

    return if (embedUrl != null) {
        """
            <!DOCTYPE html>
            <html>
            <head>
                <meta name="viewport" content="width=device-width, initial-scale=1.0">
                <style>
                    html, body {
                        margin: 0;
                        padding: 0;
                        width: 100%;
                        height: 100%;
                        background: transparent;
                        overflow: hidden;
                    }
                    iframe {
                        position: absolute;
                        top: 0;
                        left: 0;
                        width: 100%;
                        height: 100%;
                        border: 0;
                    }
                </style>
            </head>
            <body>
                <iframe
                    src="$sourceUrl"
                    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
                    allowfullscreen>
                </iframe>
            </body>
            </html>
        """.trimIndent()
    } else {
        """
            <!DOCTYPE html>
            <html>
            <head>
                <meta name="viewport" content="width=device-width, initial-scale=1.0">
                <style>
                    html, body {
                        margin: 0;
                        padding: 0;
                        width: 100%;
                        height: 100%;
                        background: transparent;
                        overflow: hidden;
                    }
                    video {
                        width: 100%;
                        height: 100%;
                        background: #000;
                    }
                </style>
            </head>
            <body>
                <video controls playsinline>
                    <source src="$sourceUrl">
                    Ваш браузер не поддерживает встроенное видео.
                </video>
            </body>
            </html>
        """.trimIndent()
    }
}

private fun String.toYouTubeEmbedUrl(): String? {
    val normalized = trim()
    if (normalized.isEmpty()) return null

    val videoId = when {
        normalized.contains("youtu.be/") -> normalized.substringAfter("youtu.be/").substringBefore("?").substringBefore("&")
        normalized.contains("youtube.com/watch") -> Regex("[?&]v=([^&]+)").find(normalized)?.groupValues?.getOrNull(1)
        normalized.contains("youtube.com/embed/") -> normalized.substringAfter("youtube.com/embed/").substringBefore("?").substringBefore("&")
        else -> null
    }?.takeIf { it.isNotBlank() } ?: return null

    return "https://www.youtube.com/embed/$videoId"
}

private fun formatSeconds(seconds: Int): String {
    val h = seconds / 3600
    val m = (seconds % 3600) / 60
    val s = seconds % 60
    return "%02d:%02d:%02d".format(h, m, s)
}

private data class ExerciseSessionSummary(
    val durationSeconds: Int,
    val calories: Int
)

private fun formatDurationHuman(seconds: Int): String {
    val h = seconds / 3600
    val m = (seconds % 3600) / 60
    val s = seconds % 60
    return when {
        h > 0 -> "${h} ч ${m} мин ${s} сек"
        m > 0 -> "${m} мин ${s} сек"
        else -> "${s} сек"
    }
}

package com.example.fitnessapp

import android.os.Bundle
import androidx.activity.ComponentActivity
